<template><div class="page messages-page"><div class="message-head"><div class="tabs"><button v-for="x in tabs" :class="{active:tab===x[1]}" @click="tab=x[1];load()">{{x[0]}}</button></div><Search/><button @click="settings=true"><Ellipsis/></button></div><div class="chips"><button v-for="x in filters" :class="{active:filter===x[1]}" @click="filter=x[1];load()">{{x[0]}}</button></div><p v-if="error" class="error">{{error}}</p><ConversationList :items="items"/><div v-if="settings" class="sheet-mask" @click.self="settings=false"><section class="sheet"><small>接待消息</small><button v-for="x in settingItems" @click="tip=x">{{x}}</button><button @click="settings=false">取消</button></section></div><div v-if="tip" class="toast" @click="tip=''">{{tip}}功能暂为占位</div></div></template>
<script setup lang="ts">import{onBeforeUnmount,onMounted,ref}from'vue';import{Search,Ellipsis}from'lucide-vue-next';import ConversationList from'../components/ConversationList.vue';const tabs=[['接待','reception'],['重要','important'],['交易','trade'],['店铺','shop'],['营销','marketing']],filters=[['在线','online'],['星标','starred'],['已停止','closed']];const tab=ref('reception'),filter=ref('online'),items=ref<any[]>([]),error=ref(''),settings=ref(false),tip=ref('');const settingItems=['接待设置','接待消息通知设置','系统消息订阅设置','系统消息通知设置','系统消息全部标记已读','加入/创建群','群聊消息通知设置','设置接收的消息类型'];let timer:number|undefined,loading=false;async function load(){if(loading)return;loading=true;try{const r=await fetch(`/api/koshop-seller/messages/conversations?tab=${tab.value}&filter=${filter.value}&page=1&pageSize=30`),j=await r.json();if(!r.ok||!j.ok)throw Error(j.message);items.value=j.items||[];error.value=''}catch(e:any){error.value=e.message||'消息加载失败'}finally{loading=false}}function stop(){if(timer!==undefined){clearInterval(timer);timer=undefined}}function start(){stop();if(!document.hidden)timer=window.setInterval(load,2500)}function visibility(){if(document.hidden)stop();else{load();start()}}onMounted(()=>{load();start();document.addEventListener('visibilitychange',visibility)});onBeforeUnmount(()=>{stop();document.removeEventListener('visibilitychange',visibility)})</script>
